import{_ as a,o as d,c as r,a2 as e}from"./chunks/framework.ZhLefgN8.js";const u=JSON.parse('{"title":"我的费率","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/trading-fees/my-fees.md","filePath":"zh-CN/stock-trading/trading-fees/my-fees.md"}'),h={name:"stock-trading/trading-fees/my-fees.md"};function o(l,t,b,i,n,s){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="我的费率" tabindex="-1">我的费率 <a class="header-anchor" href="#我的费率" aria-label="Permalink to &quot;我的费率&quot;">​</a></h1><p>「我的费率」页面显示当前账户实际适用的所有交易费率。入口在「我的」→「我的费率」，或「我的」快捷功能栏。</p><blockquote><p><strong>注意：</strong> 页面展示的是你的账户实际适用费率，不同用户因账户类型、持有权益不同，显示的费率可能有所差异。本文档仅说明各费用项的含义，具体费率以 App 内页面显示为准。</p></blockquote><h2 id="tab-切换" tabindex="-1">Tab 切换 <a class="header-anchor" href="#tab-切换" aria-label="Permalink to &quot;Tab 切换&quot;">​</a></h2><p>页面顶部按市场分 Tab：<strong>港股 / 美股 / 美股期权 / 融资利率 / 加密货币</strong></p><hr><h2 id="港股" tabindex="-1">港股 <a class="header-anchor" href="#港股" aria-label="Permalink to &quot;港股&quot;">​</a></h2><h3 id="长桥证券收费" tabindex="-1">长桥证券收费 <a class="header-anchor" href="#长桥证券收费" aria-label="Permalink to &quot;长桥证券收费&quot;">​</a></h3><table tabindex="0"><thead><tr><th>费用项</th><th>说明</th></tr></thead><tbody><tr><td>交易佣金</td><td>以账户实际费率为准，持有免佣权益的用户显示为 0（但香港政府、交易所等第三方的代收费用仍按规定收取，无法减免）</td></tr><tr><td>平台费</td><td>固定式或按比例收费，以账户实际适用方案为准</td></tr></tbody></table><h3 id="香港政府收费-代收" tabindex="-1">香港政府收费（代收） <a class="header-anchor" href="#香港政府收费-代收" aria-label="Permalink to &quot;香港政府收费（代收）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>费用项</th><th>费率</th><th>备注</th></tr></thead><tbody><tr><td>印花税</td><td>0.1% × 交易金额</td><td>每笔不足 1 元按 1 元收，如 2.01 元实收 3 元；买卖窝轮、牛熊证、ETF 时免收</td></tr></tbody></table><h3 id="香港交易所收费-代收" tabindex="-1">香港交易所收费（代收） <a class="header-anchor" href="#香港交易所收费-代收" aria-label="Permalink to &quot;香港交易所收费（代收）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>费用项</th><th>费率</th></tr></thead><tbody><tr><td>交易费</td><td>0.00565% × 交易金额，最低 0.01 HKD</td></tr><tr><td>交易征费</td><td>0.0027% × 交易金额，最低 0.01 HKD</td></tr><tr><td>交收费</td><td>香港结算所按规定收取</td></tr></tbody></table><h3 id="其他代收费" tabindex="-1">其他代收费 <a class="header-anchor" href="#其他代收费" aria-label="Permalink to &quot;其他代收费&quot;">​</a></h3><table tabindex="0"><thead><tr><th>费用项</th><th>费率</th></tr></thead><tbody><tr><td>香港证监会收费</td><td>0.0015% × 交易金额</td></tr><tr><td>会财局交易征费</td><td>0.00015% × 交易金额</td></tr><tr><td>财务汇报局收费</td><td>按比例收取</td></tr></tbody></table><hr><h2 id="美股" tabindex="-1">美股 <a class="header-anchor" href="#美股" aria-label="Permalink to &quot;美股&quot;">​</a></h2><h3 id="长桥证券收费-1" tabindex="-1">长桥证券收费 <a class="header-anchor" href="#长桥证券收费-1" aria-label="Permalink to &quot;长桥证券收费&quot;">​</a></h3><table tabindex="0"><thead><tr><th>费用项</th><th>说明</th></tr></thead><tbody><tr><td>交易佣金</td><td>以账户实际费率为准，持有免佣权益的用户显示为 0</td></tr><tr><td>平台费</td><td>固定式或按比例收费，以账户实际适用方案为准</td></tr></tbody></table><h3 id="外部机构收费-代收" tabindex="-1">外部机构收费（代收） <a class="header-anchor" href="#外部机构收费-代收" aria-label="Permalink to &quot;外部机构收费（代收）&quot;">​</a></h3><p>SEC、FINRA 等监管机构的收费是法定代收项目，由长桥作为中介代为收取，不可减免，金额通常较小。</p><table tabindex="0"><thead><tr><th>费用项</th><th>费率</th></tr></thead><tbody><tr><td>交易活动费用（TAF）</td><td>0.000195 USD / 股</td></tr><tr><td>美国证监会（SEC）费用</td><td>0.003 USD / 股，最高交易额的 7%（仅卖单收取）</td></tr><tr><td>美国金融业监管局（FINRA）费用</td><td>最低 0.01 USD，最高 9.79 USD（仅卖单收取）</td></tr><tr><td>代收股息费</td><td>免费</td></tr><tr><td>股息税</td><td>按各国税率，具体以账户所在地为准</td></tr><tr><td>ADR / DR 费用</td><td>每只股票各有不同</td></tr></tbody></table><hr><h2 id="美股期权" tabindex="-1">美股期权 <a class="header-anchor" href="#美股期权" aria-label="Permalink to &quot;美股期权&quot;">​</a></h2><p>「美股期权」Tab 内按订单类型分为两种费率方案：<strong>普通订单</strong>和<strong>低价期权</strong>。</p><h3 id="普通订单" tabindex="-1">普通订单 <a class="header-anchor" href="#普通订单" aria-label="Permalink to &quot;普通订单&quot;">​</a></h3><table tabindex="0"><thead><tr><th>费用项</th><th>说明</th></tr></thead><tbody><tr><td>交易佣金</td><td>以账户实际适用方案为准</td></tr><tr><td>平台费</td><td>以账户实际适用方案为准</td></tr></tbody></table><h3 id="低价期权" tabindex="-1">低价期权 <a class="header-anchor" href="#低价期权" aria-label="Permalink to &quot;低价期权&quot;">​</a></h3><p>低价期权（通常指期权权利金较低的合约）适用独立费率方案。</p><table tabindex="0"><thead><tr><th>费用项</th><th>说明</th></tr></thead><tbody><tr><td>交易佣金</td><td>以账户实际适用方案为准</td></tr><tr><td>平台费</td><td>以账户实际适用方案为准</td></tr></tbody></table><blockquote><p><strong>说明：</strong> 普通订单与低价期权适用不同费率档位，具体以 App 内「美股期权」Tab 显示为准。</p></blockquote><h3 id="外部机构收费-代收-1" tabindex="-1">外部机构收费（代收） <a class="header-anchor" href="#外部机构收费-代收-1" aria-label="Permalink to &quot;外部机构收费（代收）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>费用项</th><th>费率</th><th>备注</th></tr></thead><tbody><tr><td>交易活动费用（TAF）</td><td>0.002 USD / 张合约</td><td>仅卖单收取</td></tr><tr><td>美国证监会（SEC）费用</td><td>按交易金额比例收取</td><td>仅卖单收取</td></tr><tr><td>美国金融业监管局（FINRA）期权监管费</td><td>0.02975 USD / 张合约，最高不超过 6.27 USD</td><td>仅卖单收取</td></tr><tr><td>OCC 期权结算费</td><td>按结算规定收取</td><td>买卖均收取</td></tr></tbody></table><hr><h2 id="融资利率" tabindex="-1">融资利率 <a class="header-anchor" href="#融资利率" aria-label="Permalink to &quot;融资利率&quot;">​</a></h2><p>「融资利率」Tab 显示账户使用保证金融资时适用的利率。</p><h3 id="长桥证券融资利率" tabindex="-1">长桥证券融资利率 <a class="header-anchor" href="#长桥证券融资利率" aria-label="Permalink to &quot;长桥证券融资利率&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项目</th><th>说明</th></tr></thead><tbody><tr><td>港股融资利率</td><td>以账户实际适用方案为准，按日计息</td></tr><tr><td>美股融资利率</td><td>以账户实际适用方案为准，按日计息</td></tr></tbody></table><blockquote><p><strong>计息说明：</strong> 融资利率通常以年化利率展示，实际按持仓天数计算每日利息。不同账户类型、融资额度及持有权益不同，适用利率可能有所差异，以 App 内页面显示为准。</p></blockquote><hr><h2 id="加密货币" tabindex="-1">加密货币 <a class="header-anchor" href="#加密货币" aria-label="Permalink to &quot;加密货币&quot;">​</a></h2><p>「加密货币 - HAS」Tab 显示加密货币交易适用的费率。HAS 为长桥旗下加密货币交易平台。</p><h3 id="长桥证券收费-2" tabindex="-1">长桥证券收费 <a class="header-anchor" href="#长桥证券收费-2" aria-label="Permalink to &quot;长桥证券收费&quot;">​</a></h3><table tabindex="0"><thead><tr><th>费用项</th><th>说明</th></tr></thead><tbody><tr><td>交易佣金</td><td>以账户实际适用方案为准</td></tr><tr><td>平台费</td><td>以账户实际适用方案为准</td></tr></tbody></table><blockquote><p><strong>说明：</strong> 加密货币交易费率以 App 内「加密货币 - HAS」Tab 显示为准，不同交易对或交易量可能适用不同费率档位。</p></blockquote><hr><h2 id="费率显示与调整规则" tabindex="-1">费率显示与调整规则 <a class="header-anchor" href="#费率显示与调整规则" aria-label="Permalink to &quot;费率显示与调整规则&quot;">​</a></h2><ul><li>页面显示的是<strong>当前账户实际适用费率</strong>，若持有特殊权益（如终生免佣），相应费率显示为 0</li><li>收费及利率如有调整，恕不另行通知，以页面最新显示为准</li><li>点击各费用项右侧「了解示例」可查看具体计算示例</li></ul>',48)])])}const q=a(h,[["render",o]]);export{u as __pageData,q as default};
